import { useState, useEffect, useCallback } from 'react';
import { getPendingTransactions, markSynced } from '../utils/offlineStore';
import { api } from '../utils/api';
import toast from 'react-hot-toast';

export function useSync() {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [pendingCount, setPendingCount] = useState(0);
  const [syncing, setSyncing] = useState(false);

  useEffect(() => {
    const on = () => setIsOnline(true);
    const off = () => setIsOnline(false);
    window.addEventListener('online', on);
    window.addEventListener('offline', off);
    return () => { window.removeEventListener('online', on); window.removeEventListener('offline', off); };
  }, []);

  const refreshPending = useCallback(async () => {
    const pending = await getPendingTransactions();
    setPendingCount(pending.length);
  }, []);

  useEffect(() => { refreshPending(); }, [refreshPending]);

  const sync = useCallback(async () => {
    if (!isOnline || syncing) return;
    const pending = await getPendingTransactions();
    if (!pending.length) return;

    setSyncing(true);
    try {
      const results = await api.syncTransactions(pending);
      let success = 0;
      for (const r of results.results) {
        if (r.status === 'SUCCESS' || r.status === 'DUPLICATE') {
          await markSynced(r.offline_id);
          if (r.status === 'SUCCESS') success++;
        }
      }
      await refreshPending();
      if (success > 0) toast.success(`${success} entries synced`);
    } catch (err) {
      toast.error('Sync failed: ' + err.message);
    } finally {
      setSyncing(false);
    }
  }, [isOnline, syncing, refreshPending]);

  return { isOnline, pendingCount, syncing, sync, refreshPending };
}
